mapper.select:
SELECT id, order_no, product_name, product_desc, employee_name, points_cost, exchange_time, status, created_at, updated_at, created_by, updated_by, deleted, version FROM exchange_record WHERE deleted = 0
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR employee_name LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}
AND exchange_time >= #{startTime}
AND exchange_time <= #{endTime}
ORDER BY exchange_time DESC
